function ProblemList() {
  const [items, setItems] = useState(['a', 'b', 'c']);

  const removeFirst = () => {
    setItems(items.slice(1)); // remove first item
  };

  return (
    <div>
      <button onClick={removeFirst}>Remove first</button>
      <ul>
        {items.map((item, index) => (
          // ❌ Bad: index as key
          <li key={index}>
            <input defaultValue={item} />
          </li>
        ))}
      </ul>
    </div>
  );
}
